sql:
SELECT COUNT(*) 
FROM stock_history 
WHERE product_id = 0 AND source_website = 'https://www.airliftexpress.com';

SELECT product_id, MAX(date) AS latest_stock_date
FROM stock_history
GROUP BY product_id;

SELECT COUNT(*) 
FROM products 
WHERE supplier_id = (SELECT supplier_id FROM suppliers WHERE supplier_name = 'AirLift Express');

SELECT product_id, price
FROM price_history
ORDER BY date DESC;
